examples.toCode:
// TypeScript
interface User {
  id: number;
  name: string;
  email: string;
}

async function getUser(id: number): Promise<string> {
  const res = await fetch('/api/users/' + id);
  const user: User = await res.json();
  return user.name.toUpperCase(); // safe — name is required
}
